import sys

def read_int():
    return int(sys.stdin.readline())

def read_ints():
    return map(int, sys.stdin.readline().split())

def read_int_list():
    return list(read_ints())

def solve(n, xs, ys):
    min_x = min(xs)
    min_y = min(ys)
    max_x = max(xs)
    max_y = max(ys)
    return (max_x - min_x)**2

def main():
    n = read_int()
    xs = read_int_list()
    ys = read_int_list()
    print(solve(n, xs, ys))


if __name__ == '__main__':
    main()
